/* eslint-disable no-undef */
import { open as openKeyboard } from '../webkit/keyboard';
import { isWebView } from '../webkit/utils';
import { hasTouchSupport } from './isMobile';

/**
 * Provide functionality autofocus programmatically and open keyboard in webviews on first render
 * @param {HTMLInputElement} input
 * @param {boolean} [firstRender]
 */
const autofocus = (input, firstRender = true) => {
  if (firstRender) {
    openKeyboard(input);
  }
  if (!isWebView() && !hasTouchSupport() && typeof input.focus === 'function') {
    input.focus();
  }
};

export {
  autofocus,
};
